insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-3013', 'low glute bridge on floor', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','core']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your arms by your sides, palms facing down.','Engage your glutes and core, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.','Pause for a moment at the top, squeezing your glutes.','Slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'u0cNiij'),
  ('db-1352', 'lower back curl', 'Back', 'Body Weight', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Lie flat on your stomach with your legs extended and your arms by your sides.','Engage your glutes and hamstrings, and slowly lift your upper body off the ground, curling your back upwards.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ANbbry2'),
  ('db-3582', 'lunge with jump', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart.','Take a step forward with your right foot, lowering your body into a lunge position.','Push off with your right foot and jump into the air, switching the position of your feet mid-air.','Land softly with your left foot forward and immediately lower your body into a lunge position.','Continue alternating between lunges and jumps for the desired number of repetitions.']::text[], 'PM1PZjg'),
  ('db-1688', 'lunge with twist', 'Core', 'Body Weight', 'abs', ARRAY['quadriceps','glutes','hamstrings']::text[], ARRAY['Start by standing with your feet shoulder-width apart.','Take a step forward with your right foot, lowering your body into a lunge position.','As you lunge, twist your torso to the right, bringing your left elbow towards your right knee.','Pause for a moment, then return to the starting position.','Repeat on the other side, stepping forward with your left foot and twisting your torso to the left.','Continue alternating sides for the desired number of repetitions.']::text[], 'K9VL0Jq'),
  ('db-0613', 'lying (side) quads stretch', 'Legs', 'Body Weight', 'quads', ARRAY['hamstrings']::text[], ARRAY['Lie on your side with your legs straight.','Bend your top leg and grab your ankle or foot with your hand.','Gently pull your ankle or foot towards your glutes until you feel a stretch in your quads.','Hold the stretch for 20-30 seconds.','Release the stretch and repeat on the other side.']::text[], 'BWnJR72'),
  ('db-2312', 'lying elbow to knee', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.','At the same time, extend your right leg straight out and lift it off the ground.','Pause for a moment, then return to the starting position.','Repeat the movement, this time bringing your left elbow towards your right knee and extending your left leg.','Continue alternating sides for the desired number of repetitions.']::text[], 'AQIhRjM'),
  ('db-0620', 'lying leg raise flat bench', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on a flat bench with your back pressed against it.','Place your hands under your glutes for support.','Keep your legs straight and together, and lift them up towards the ceiling.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'WhuFnR7'),
  ('db-0865', 'lying leg-hip raise', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Place your hands under your glutes for support.','Engage your core and lift your legs off the ground, raising them towards the ceiling.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '9IxJdtC'),
  ('db-1301', 'machine inner chest press', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your back flat against the pad.','Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.','Push the handles forward until your arms are fully extended, exhaling during the movement.','Pause for a moment at the end of the movement, then slowly return to the starting position, inhaling as you do so.','Repeat for the desired number of repetitions.']::text[], 'wDN97Ca'),
  ('db-0624', 'march sit (wall)', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your back against a wall and your feet hip-width apart.','Slowly slide your back down the wall until your knees are bent at a 90-degree angle.','Lift your right foot off the ground and bring your knee towards your chest.','Lower your right foot back down and lift your left foot off the ground, bringing your knee towards your chest.','Continue alternating between lifting your right and left foot for the desired number of repetitions.']::text[], 'sVQCCeG'),
  ('db-1353', 'medicine ball catch and overhead throw', 'Back', 'Medicine Ball', 'lats', ARRAY['shoulders','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a medicine ball in both hands at chest level.','Bend your knees slightly and engage your core.','Lower your body into a squat position, keeping your back straight and chest up.','Explosively extend your hips and legs, while simultaneously throwing the medicine ball overhead.','Release the ball at the top of the movement and catch it on the way down.','Lower your body back into the squat position and repeat for the desired number of repetitions.']::text[], 'PsVS1QP'),
  ('db-1302', 'medicine ball chest pass', 'Chest', 'Medicine Ball', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart, holding the medicine ball at chest level.','Extend your arms forward, pushing the medicine ball away from your chest with force.','As you release the ball, follow through with your arms and torso, transferring your weight from your back foot to your front foot.','Catch the ball as it rebounds off the wall or partner, and immediately repeat the movement.','Continue for the desired number of repetitions.']::text[], 'aDoFKrE'),
  ('db-1303', 'medicine ball chest push from 3 point stance', 'Chest', 'Medicine Ball', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Start in a 3 point stance with one hand on the medicine ball and the other hand on the ground.','Extend your legs and position your body in a straight line.','Lower your chest towards the ground while keeping your back straight.','Push the medicine ball away from your body, extending your arm fully.','Return to the starting position and repeat for the desired number of repetitions.']::text[], 'dCJnuVq'),
  ('db-1304', 'medicine ball chest push multiple response', 'Chest', 'Medicine Ball', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a medicine ball at chest level.','Extend your arms forward, pushing the medicine ball away from your chest.','Pause for a moment, then slowly bring the medicine ball back to your chest.','Repeat for the desired number of repetitions.']::text[], '7aolH9D'),
  ('db-1305', 'medicine ball chest push single response', 'Chest', 'Medicine Ball', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart, holding the medicine ball at chest level.','Extend your arms forward, pushing the medicine ball away from your chest.','Pause for a moment, then slowly bring the medicine ball back to your chest.','Repeat for the desired number of repetitions.']::text[], 'jeHtrlO'),
  ('db-1312', 'medicine ball chest push with run release', 'Chest', 'Medicine Ball', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a medicine ball at chest level.','Step forward with your right foot and simultaneously push the medicine ball forward, extending your arms fully.','As you push the ball forward, release it and let it roll forward.','Quickly run forward and catch the ball before it hits the ground.','Once you catch the ball, bring it back to your chest and repeat the movement with your left foot forward.','Continue alternating legs and repeating the exercise for the desired number of repetitions.']::text[], 'pX9Elbe'),
  ('db-1701', 'medicine ball close grip push up', 'Arms', 'Medicine Ball', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Start in a high plank position with your hands on the medicine ball, shoulder-width apart.','Lower your body towards the ground by bending your elbows, keeping them close to your sides.','Push back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '8K7m2SS'),
  ('db-1354', 'medicine ball overhead slam', 'Back', 'Medicine Ball', 'upper back', ARRAY['shoulders','core']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a medicine ball with both hands above your head.','Engage your core and keep your back straight.','Bend your knees slightly and forcefully slam the medicine ball down to the ground in front of you.','As you slam the ball down, use your entire body to generate power, including your shoulders and core.','Catch the ball on the bounce and repeat for the desired number of repetitions.']::text[], 'oHg8eop'),
  ('db-1750', 'medicine ball supine chest throw', 'Arms', 'Medicine Ball', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Lie flat on your back on a bench with your knees bent and feet flat on the ground.','Hold the medicine ball with both hands, extending your arms straight up above your chest.','Lower the medicine ball towards your chest, keeping your elbows close to your body.','Explosively push the medicine ball upwards, extending your arms fully and throwing the ball as high as possible.','Catch the medicine ball and repeat for the desired number of repetitions.']::text[], 'Al3tP0D'),
  ('db-0627', 'mixed grip chin-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with an underhand grip (palms facing towards you) and your hands slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your feet off the ground.','Engage your back muscles and pull your body up towards the bar, leading with your chest.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position with control.','Repeat for the desired number of repetitions.']::text[], 'T8UpLkb'),
  ('db-3217', 'modified hindu push-up (male)', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet hip-width apart.','Lower your body towards the ground, bending your elbows and keeping your core engaged.','As you lower your body, shift your weight back and lift your hips up towards the ceiling, creating an inverted V shape with your body.','Continue to lower your body until your chest is just above the ground, then reverse the movement, pushing your hips back down and extending your arms to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'epOSYUZ'),
  ('db-1421', 'modified push up to lower arms', 'Arms', 'Body Weight', 'forearms', ARRAY['triceps','chest','shoulders']::text[], ARRAY['Start in a push-up position with your hands directly under your shoulders and your body in a straight line.','Lower your body down towards the ground by bending your elbows, keeping them close to your sides.','Once your elbows are at a 90-degree angle, lower your forearms to the ground, keeping your elbows directly under your shoulders.','Pause for a moment, then push through your palms to lift your forearms back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'arvaszz'),
  ('db-0628', 'monster walk', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Place a resistance band around your ankles.','Stand with your feet shoulder-width apart and slightly bend your knees.','Take a step to the side with your right foot, maintaining tension on the resistance band.','Follow with your left foot, stepping to the side to return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'O95afRA'),
  ('db-0630', 'mountain climber', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['core','shoulders','triceps']::text[], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line.','Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest.','Continue alternating legs in a running motion, keeping your hips low and your core engaged.','Maintain a steady pace and breathe evenly throughout the exercise.','Repeat for the desired number of repetitions.']::text[], 'RJgzwny'),
  ('db-0631', 'muscle up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','triceps','shoulders','chest']::text[], ARRAY['Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.','Engage your core and pull your body up towards the bar, leading with your chest.','As you reach the top of the movement, transition your grip so that your palms are facing towards you.','Continue pulling yourself up until your chest is above the bar and your arms are fully flexed.','Reverse the movement by slowly lowering yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'yJUHKTn'),
  ('db-1401', 'muscle-up (on vertical bar)', 'Back', 'Body Weight', 'lats', ARRAY['biceps','triceps','forearms']::text[], ARRAY['Start by hanging from a vertical bar with your palms facing away from you and your arms fully extended.','Engage your core and pull your body up towards the bar, leading with your chest.','As you pull yourself up, lean back slightly and bring your elbows towards your sides.','Continue pulling until your chest reaches the bar and your elbows are fully bent.','Pause for a moment at the top, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Af0EW2I'),
  ('db-2328', 'narrow push-up on exercise ball', 'Arms', 'Stability Ball', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Place the stability ball on the ground and position yourself in a push-up position with your hands on the ball, slightly narrower than shoulder-width apart.','Engage your core and keep your body in a straight line from head to toe.','Lower your chest towards the ball by bending your elbows, keeping them close to your body.','Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], '4cWjYEN'),
  ('db-1403', 'neck side stretch', 'Other', 'Body Weight', 'levator scapulae', ARRAY['trapezius','sternocleidomastoid']::text[], ARRAY['Stand or sit up straight with your shoulders relaxed.','Tilt your head to one side, bringing your ear towards your shoulder.','Hold the stretch for 15-30 seconds.','Repeat on the other side.','Perform 2-4 sets on each side.']::text[], 'x2chWLO'),
  ('db-0634', 'negative crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'szIn2UK'),
  ('db-1495', 'oblique crunch v. 2', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Lie on your back with your knees bent and feet flat on the ground.','Place your hands behind your head or cross them over your chest.','Engage your abs and lift your shoulder blades off the ground, rotating your torso to one side.','Pause for a moment, then lower your shoulder blades back down to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'cJgSTmh'),
  ('db-0635', 'oblique crunches floor', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Lie on your back with your knees bent and feet flat on the floor.','Place your hands behind your head or cross them over your chest.','Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side.','Pause for a moment, then lower your shoulder blades back down to the floor.','Repeat on the other side, alternating sides with each repetition.']::text[], 'QUDd8WS'),
  ('db-0636', 'olympic barbell hammer curl', 'Arms', 'Olympic Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold an Olympic barbell with an overhand grip.','Let the barbell hang at arm''s length in front of your thighs, with your palms facing your body.','Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.','Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale and slowly begin to lower the barbell back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'o1ntciW'),
  ('db-0637', 'olympic barbell triceps extension', 'Arms', 'Olympic Barbell', 'triceps', ARRAY['shoulders']::text[], ARRAY['Start by standing with your feet shoulder-width apart and holding the barbell with an overhand grip.','Raise the barbell above your head, fully extending your arms.','Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.','Pause for a moment, then extend your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wu5LXwz'),
  ('db-1355', 'one arm against wall', 'Back', 'Body Weight', 'lats', ARRAY['shoulders','triceps']::text[], ARRAY['Stand facing a wall with your feet shoulder-width apart.','Extend one arm straight out in front of you and place your palm against the wall.','Engage your core and lean your body forward, keeping your arm straight and your back flat.','Slowly push against the wall with your palm, activating your lat muscles.','Hold the position for a few seconds, then release and repeat with the other arm.']::text[], 'ZZTGMKh'),
  ('db-0638', 'one arm chin-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Stand facing a pull-up bar with your feet shoulder-width apart.','Reach up and grab the bar with an underhand grip, with one hand gripping the bar and the other hand holding your wrist for support.','Hang from the bar with your arm fully extended, keeping your body straight and your core engaged.','Pull yourself up towards the bar by bending your elbow and squeezing your back muscles.','Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions, then switch arms and repeat.']::text[], 'HjdqmZa'),
  ('db-0639', 'one arm dip', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Stand facing away from a bench or chair, with your feet shoulder-width apart.','Place one hand on the bench or chair behind you, fingers pointing towards your body.','Extend your legs out in front of you, keeping your heels on the ground.','Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair.','Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position.','Repeat for the desired number of repetitions, then switch sides and repeat with the other arm.']::text[], 'FAoIFMw'),
  ('db-0640', 'one arm slam (with medicine ball)', 'Core', 'Medicine Ball', 'abs', ARRAY['shoulders','back']::text[], ARRAY['Stand with your feet shoulder-width apart, holding the medicine ball with one hand in front of your waist.','Bend your knees slightly and engage your core.','Raise the medicine ball above your head, fully extending your arm.','Forcefully slam the medicine ball down to the ground, using your core and shoulders to generate power.','Catch the medicine ball on the bounce and repeat for the desired number of repetitions.']::text[], 'jCrtE9b'),
  ('db-1773', 'one arm towel row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.','Bend forward at the waist, keeping your back straight and your core engaged.','Extend your arm fully, allowing the towel to hang in front of you.','Pull the towel towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the towel back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'bKWbrTA'),
  ('db-1386', 'one leg donkey calf raise', 'Legs', 'Body Weight', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing forward.','Place your hands on a stable surface for support, such as a wall or a bar.','Lift one leg off the ground, keeping your knee slightly bent.','Raise your heel as high as possible, using your calf muscles.','Pause for a moment at the top, then slowly lower your heel back down.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'A2upspL'),
  ('db-1387', 'one leg floor calf raise', 'Legs', 'Body Weight', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand with your feet hip-width apart and place your hands on a wall or sturdy object for balance.','Lift one foot off the ground and balance on the other foot.','Slowly raise your heel off the ground, lifting your body up onto the ball of your foot.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], '0jp9Rlz'),
  ('db-1476', 'one leg squat', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Extend one leg forward, keeping it off the ground.','Bend your standing leg and lower your body down as if sitting back into a chair.','Keep your chest up and your back straight.','Push through your heel to return to the starting position.','Repeat with the other leg.']::text[], 'C31LMnP'),
  ('db-0641', 'otis up', 'Core', 'Weighted', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UVL20oz'),
  ('db-0642', 'outside leg kick push-up', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.','Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.','As you push back up, kick one leg out to the side, extending it fully and engaging your glutes.','Return your leg to the starting position and repeat the push-up, alternating legs with each repetition.','Continue alternating leg kicks and push-ups for the desired number of repetitions.']::text[], 'jNU1gFQ'),
  ('db-0643', 'overhead triceps stretch', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand or sit upright with your feet shoulder-width apart.','Extend one arm overhead, bending at the elbow so that your hand reaches towards the opposite shoulder blade.','With your other hand, gently pull the elbow of the extended arm towards the opposite side of your head, feeling a stretch in your triceps.','Hold the stretch for 15-30 seconds, then release.','Repeat on the other side.']::text[], 'Z5YStHW'),
  ('db-3147', 'pelvic tilt', 'Core', 'Body Weight', 'abs', ARRAY['lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands by your sides.','Engage your abs and tilt your pelvis upward, pressing your lower back into the ground.','Hold this position for a few seconds, focusing on contracting your abs.','Release the tilt and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NKJ8o6x'),
  ('db-1422', 'pelvic tilt into bridge', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','core']::text[], ARRAY['Lie on your back with your knees bent and feet flat on the ground.','Place your arms by your sides with your palms facing down.','Engage your glutes and core muscles.','Tilt your pelvis upward, lifting your hips off the ground.','Hold the bridge position for a few seconds.','Slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'D9qe7CM'),
  ('db-1388', 'peroneals stretch', 'Legs', 'Rope', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Loop the rope around the ball of your foot and hold the ends of the rope with your hands.','Gently pull the rope towards you, flexing your foot and stretching your calf muscles.','Hold the stretch for 15-30 seconds.','Release the tension on the rope and repeat the stretch on the other leg.','Repeat for the desired number of repetitions.']::text[], 'XhfS1DZ'),
  ('db-3662', 'pike-to-cobra push-up', 'Legs', 'Body Weight', 'glutes', ARRAY['core','shoulders','triceps']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.','Engage your core and lift your hips up towards the ceiling, forming an inverted V shape with your body.','Lower your upper body towards the ground by bending your elbows, keeping them close to your body.','As you lower down, shift your weight forward and transition into a cobra pose by straightening your arms and lifting your chest up.','Reverse the movement by bending your elbows and lowering your chest back down towards the ground.','Push through your hands to return to the inverted V position.','Continue the movement by lowering your hips back down towards the ground, returning to the starting push-up position.','Repeat for the desired number of repetitions.']::text[], 'XPUDTt7'),
  ('db-1306', 'plyo push up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart.','Lower your chest towards the ground by bending your elbows, keeping your body in a straight line.','Push explosively off the ground, using your chest muscles to propel your upper body off the ground.','Land softly with your hands back in the starting position.','Repeat for the desired number of repetitions.']::text[], 'Snj1wSv'),
  ('db-1687', 'posterior step to overhead reach', 'Core', 'Body Weight', 'abs', ARRAY['glutes','hamstrings','quadriceps','shoulders']::text[], ARRAY['Stand with your feet hip-width apart and your arms by your sides.','Take a step back with your right foot, landing on the ball of your foot.','Bend your left knee and lower your body into a lunge position.','As you lower into the lunge, simultaneously reach your arms overhead.','Pause for a moment at the bottom of the lunge, then return to the starting position by pushing through your left heel and bringing your right foot forward.','Repeat the movement on the other side, stepping back with your left foot and bending your right knee.','Continue alternating sides for the desired number of repetitions.']::text[], 'ErqK3UL'),
  ('db-1389', 'posterior tibialis stretch', 'Legs', 'Rope', 'calves', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Loop the rope around the ball of your foot and hold the ends of the rope with your hands.','Gently pull the rope towards you, flexing your foot and stretching your calf muscles.','Hold the stretch for 20-30 seconds.','Release the tension on the rope and relax your foot.','Repeat the stretch on the other leg.']::text[], 'DEEqoI2'),
  ('db-3119', 'potty squat', 'Core', 'Body Weight', 'abs', ARRAY['quadriceps','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing slightly outward.','Lower your body down by bending your knees and pushing your hips back as if you were sitting on a chair.','Keep your chest up and your back straight throughout the movement.','Lower yourself until your thighs are parallel to the ground or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], '75Bgtjy'),
  ('db-3132', 'potty squat with support', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing slightly outward.','Hold onto a stable support, such as a chair or wall, for balance.','Lower your body down into a squat position by bending your knees and pushing your hips back.','Keep your chest up and your back straight throughout the movement.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'b63ZzGe'),
  ('db-0648', 'power clean', 'Legs', 'Barbell', 'hamstrings', ARRAY['glutes','quadriceps','calves']::text[], ARRAY['Start with the barbell on the ground in front of you, with your feet shoulder-width apart.','Bend down and grip the barbell with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and chest up as you lift the barbell off the ground, extending your hips and knees.','As the barbell reaches your mid-thigh, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.','As the barbell reaches its highest point, quickly drop underneath it, rotating your elbows around and catching the barbell on your shoulders in a front squat position.','Stand up with the barbell, fully extending your hips and knees.','Lower the barbell back down to the starting position, keeping control of the weight throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'SiWCcTN'),
  ('db-3665', 'power point plank', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','triceps','glutes']::text[], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.','Engage your core and squeeze your glutes to maintain a stable position.','Lower your body down onto your forearms, one arm at a time, maintaining a straight line from head to toe.','Hold this position for the desired amount of time, keeping your core and glutes engaged.','To return to the starting position, push through your forearms and lift your body back up into a high plank position.','Repeat for the desired number of repetitions.']::text[], 'hCjGsRQ'),
  ('db-3203', 'prisoner half sit-up (male)', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'mgejmGP'),
  ('db-1707', 'prone twist on stability ball', 'Core', 'Stability Ball', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground.','Place your hands behind your head or cross them over your chest.','Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight.','Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement.','Pause for a moment, then return to the starting position.','Repeat the rotation to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], '1IG6gVF'),
  ('db-0651', 'pull up (neutral grip)', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Hang from a pull-up bar with a neutral grip (palms facing each other) and your arms fully extended.','Engage your core and squeeze your shoulder blades together.','Pull your body up towards the bar by bending your elbows and driving your elbows down towards your hips.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position with control.','Repeat for the desired number of repetitions.']::text[], '0V2YQjW'),
  ('db-0650', 'pull-in (on stability ball)', 'Core', 'Stability Ball', 'abs', ARRAY['hip flexors']::text[], ARRAY['Start by sitting on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Place your hands on the sides of the stability ball for support.','Engage your abs and slowly roll your hips forward, bringing your knees towards your chest.','Pause for a moment at the top of the movement, then slowly extend your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UQr48Oi'),
  ('db-0652', 'pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Hang from a pull-up bar with your palms facing away from you and your arms fully extended.','Engage your core and squeeze your shoulder blades together.','Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar.','Pause at the top of the movement, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'lBDjFxJ'),
  ('db-1689', 'push and pull bodyweight', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','deltoids']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your body in a straight line.','Lower your chest towards the ground by bending your elbows, keeping your body straight.','Push through your palms to extend your arms and return to the starting position.','From the push-up position, pull your chest towards the ground by bending your elbows, keeping your body straight.','Push through your palms to extend your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'wXvUZC8'),
  ('db-3638', 'push to run', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and your body in a straight line.','Lower your chest towards the ground by bending your elbows, keeping your body straight.','Push through your hands to extend your arms and return to the starting position.','Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest.','Continue alternating knees as fast as you can while maintaining good form.','Continue for the desired duration or number of repetitions.']::text[], 'PrQbjvB'),
  ('db-1307', 'push up on bosu ball', 'Chest', 'Bosu Ball', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Place the bosu ball on the ground with the flat side facing up.','Position yourself in a push-up position with your hands on the outer edges of the bosu ball.','Engage your core and lower your body down towards the bosu ball by bending your elbows.','Push yourself back up to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'wVompEp'),
  ('db-0662', 'push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','deltoids','core']::text[], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.','Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line.','Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'I4hDWkc'),
  ('db-0653', 'push-up (bosu ball)', 'Chest', 'Bosu Ball', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Place the bosu ball on the ground with the flat side facing up.','Position yourself in a push-up position with your hands on the outer edges of the bosu ball.','Engage your core and lower your body down towards the bosu ball by bending your elbows.','Push yourself back up to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], '2kr2lWy'),
  ('db-0655', 'push-up (on stability ball)', 'Chest', 'Stability Ball', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.','Extend your legs straight out behind you, balancing on your toes.','Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.','Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'Y4BRNQF'),
  ('db-0656', 'push-up (on stability ball)', 'Chest', 'Stability Ball', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.','Extend your legs straight out behind you, balancing on your toes.','Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.','Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'tgryw5Y'),
  ('db-0659', 'push-up (wall)', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','deltoids']::text[], ARRAY['Stand facing a wall, about arm''s length away.','Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.','Step back a few feet, keeping your body straight and your feet hip-width apart.','Bend your elbows and lower your chest towards the wall, keeping your body in a straight line.','Push back up to the starting position, straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'LEH9jxP'),
  ('db-0658', 'push-up (wall) v. 2', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Stand facing a wall, about arm''s length away.','Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.','Step back with your feet, keeping them hip-width apart.','Engage your core and keep your body in a straight line from head to heels.','Bend your elbows and lower your chest towards the wall, keeping your body straight.','Pause for a moment, then push yourself back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NCmbLCw'),
  ('db-0660', 'push-up close-grip off dumbbell', 'Arms', 'Dumbbell', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Start in a push-up position with your hands placed close together, directly under your shoulders.','Hold a dumbbell in each hand, resting them on the ground.','Lower your body towards the ground by bending your elbows, keeping them close to your sides.','Push through your palms to extend your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'KZXAtKQ'),
  ('db-0661', 'push-up inside leg kick', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.','Lower your body towards the ground by bending your elbows, keeping your back straight and your core engaged.','As you push back up, lift one leg off the ground and kick it out to the side, keeping it straight.','Lower your leg back down and repeat the push-up, then switch to the other leg.','Continue alternating leg kicks with each push-up repetition.']::text[], '0br45wL'),
  ('db-0663', 'push-up medicine ball', 'Chest', 'Medicine Ball', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a high plank position with your hands on the medicine ball, shoulder-width apart.','Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.','Push through your palms to extend your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'W8KAlkI'),
  ('db-1467', 'push-up on lower arms', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Start in a plank position with your forearms on the ground and elbows directly below your shoulders.','Engage your core and keep your body in a straight line from head to toe.','Lower your chest towards the ground by bending your elbows, keeping them close to your body.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '4Jt8QsQ'),
  ('db-3145', 'push-up plus', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.','Lower your body towards the ground by bending your elbows, keeping them close to your sides.','Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up.','At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling.','Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'pvBMLHA'),
  ('db-0664', 'push-up to side plank', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','chest','triceps']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and your body in a straight line.','Lower your body towards the ground by bending your elbows, keeping your core engaged.','Push back up to the starting position.','Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling.','Hold the side plank position for a few seconds, then return to the starting position.','Repeat the push-up and side plank on the opposite side.','Continue alternating sides for the desired number of repetitions.']::text[], 'KhHJ338'),
  ('db-3533', 'quads', 'Legs', 'Body Weight', 'quads', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart.','Lower your body by bending your knees and pushing your hips back as if sitting on a chair.','Keep your chest up and your back straight.','Lower yourself until your thighs are parallel to the ground.','Push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], '6YUfHPL'),
  ('db-3201', 'quarter sit-up', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'enxnJcM'),
  ('db-3552', 'quick feet v. 2', 'Legs', 'Body Weight', 'quads', ARRAY['calves','hamstrings']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms by your sides.','Begin by rapidly moving your feet up and down, as if you were running in place.','Keep your movements quick and light, focusing on staying on the balls of your feet.','Continue for the desired duration or number of repetitions.']::text[], 'mweqJin'),
  ('db-0666', 'raise single arm push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.','Extend one arm straight out to the side, parallel to the ground.','Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.','Push back up to the starting position, using your chest muscles to lift your body.','Repeat with the other arm extended.']::text[], '13TpY4H'),
  ('db-0668', 'rear decline bridge', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Lie on your back with your feet flat on the ground and your knees bent.','Place your arms by your sides with your palms facing down.','Engage your glutes and hamstrings, and lift your hips off the ground until your body forms a straight line from your knees to your shoulders.','Hold this position for a few seconds, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'UpAlold'),
  ('db-0669', 'rear deltoid stretch', 'Shoulders', 'Body Weight', 'delts', ARRAY['trapezius','rhomboids']::text[], ARRAY['Stand tall with your feet shoulder-width apart.','Extend your right arm across your chest, placing your left hand on your right elbow.','Gently pull your right arm towards your left shoulder, feeling a stretch in your right shoulder.','Hold the stretch for 15-30 seconds, then release.','Repeat on the other side.']::text[], 'xifhB5W'),
  ('db-0670', 'rear pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your body straight.','Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'CbFSYC1'),
  ('db-1582', 'reclining big toe pose with rope', 'Legs', 'Rope', 'hamstrings', ARRAY['calves','glutes']::text[], ARRAY['Lie on your back with your legs extended and your arms by your sides.','Loop the rope around the ball of your right foot and hold the ends of the rope with your hands.','Slowly raise your right leg towards your chest, keeping your knee straight and your foot flexed.','Hold the stretch for a few seconds, then slowly lower your leg back down to the starting position.','Repeat with your left leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'K5xgdvI'),
  ('db-3236', 'resistance band hip thrusts on knees (female)', 'Legs', 'Resistance Band', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Start by kneeling on the ground with your knees hip-width apart and your feet flexed.','Wrap the resistance band around your thighs, just above your knees.','Place your hands on your hips or extend them out in front of you for balance.','Engage your glutes and core muscles.','Push your hips forward and squeeze your glutes as you lift your knees off the ground, extending your hips until your thighs are parallel to the ground.','Hold the position for a moment, then slowly lower your knees back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Pjbc0Kt'),
  ('db-3007', 'resistance band leg extension', 'Legs', 'Resistance Band', 'quads', ARRAY['hamstrings']::text[], ARRAY['Attach the resistance band to a sturdy anchor point and secure it around your ankle.','Stand facing the anchor point with your feet shoulder-width apart.','Keeping your core engaged and your upper body stable, extend your leg straight out in front of you.','Pause for a moment at the top, then slowly return your leg to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'Y1MsI1l'),
  ('db-3123', 'resistance band seated biceps curl', 'Arms', 'Resistance Band', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a chair or bench with your back straight and feet flat on the ground.','Hold the resistance band with an underhand grip, palms facing up, and arms extended down by your sides.','Keeping your upper arms stationary, exhale and curl the resistance band up towards your shoulders.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the resistance band back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'XFc3vpY'),
  ('db-3124', 'resistance band seated chest press', 'Chest', 'Resistance Band', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on a chair or bench with your back straight and feet flat on the ground.','Hold the resistance band handles in each hand, with your palms facing down and elbows bent at a 90-degree angle.','Extend your arms forward, pushing the resistance band away from your chest.','Pause for a moment at the end of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], '4x5Okof'),
  ('db-3006', 'resistance band seated hip abduction', 'Legs', 'Resistance Band', 'abductors', ARRAY['glutes','hamstrings']::text[], ARRAY['Sit on a chair or bench with your back straight and feet flat on the ground.','Wrap the resistance band around your thighs, just above your knees.','Place your hands on the sides of the chair or bench for support.','Engage your abductors (outer thigh muscles) and slowly push your knees apart, against the resistance of the band.','Pause for a moment at the end of the movement, then slowly bring your knees back together.','Repeat for the desired number of repetitions.']::text[], '0xDpB4L'),
  ('db-3122', 'resistance band seated shoulder press', 'Shoulders', 'Resistance Band', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Sit on a chair or bench with your back straight and feet flat on the ground.','Hold the resistance band with both hands, palms facing forward, and bring it up to shoulder level.','Press the band overhead, extending your arms fully.','Pause for a moment at the top, then slowly lower the band back down to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'S93zLTG'),
  ('db-3144', 'resistance band seated straight back row', 'Back', 'Resistance Band', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Sit on the floor with your legs extended and loop the resistance band around your feet.','Hold the ends of the resistance band with your hands, palms facing each other.','Keep your back straight and lean slightly back, engaging your core.','Pull the resistance band towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Nu7jqFE'),
  ('db-0872', 'reverse crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your arms extended along your sides.','Bend your knees and lift your feet off the ground, bringing your thighs perpendicular to the floor.','Contract your abs and curl your hips off the floor, bringing your knees towards your chest.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'nCU1Ekp'),
  ('db-0672', 'reverse dip', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Position yourself between two parallel bars with your arms fully extended and your body straight.','Lower your body by bending your elbows until your upper arms are parallel to the ground.','Pause for a moment, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'NZ5Qqkz'),
  ('db-0673', 'reverse grip machine lat pulldown', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.','Grasp the handles with an underhand grip, slightly wider than shoulder-width apart.','Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back.','Pull the handles down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ecpY0rH'),
  ('db-0674', 'reverse grip pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with an underhand grip, hands shoulder-width apart.','Hang from the bar with your arms fully extended and your body straight.','Engage your back muscles and pull your body up towards the bar, leading with your chest.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'YAk5dIw'),
  ('db-0675', 'reverse hyper extension (on stability ball)', 'Legs', 'Stability Ball', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Lie face down on a stability ball with your hips resting on the ball and your legs extended straight behind you.','Place your hands on the ground in front of you for stability.','Engaging your glutes and hamstrings, lift your legs up towards the ceiling as high as you can.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vM5YS2g'),
  ('db-1423', 'reverse hyper on flat bench', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Lie face down on a flat bench with your hips at the edge and your legs hanging off the bench.','Hold onto the bench for stability.','Keeping your legs straight, raise them up towards the ceiling as high as you can.','Squeeze your glutes at the top of the movement.','Slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OrETs32'),
  ('db-3663', 'reverse plank with leg lift', 'Core', 'Body Weight', 'abs', ARRAY['glutes','hamstrings','shoulders']::text[], ARRAY['Sit on the ground with your legs extended in front of you and your hands resting on the ground behind you, fingers pointing towards your feet.','Press through your hands and lift your hips off the ground, coming into a reverse plank position.','Engage your core and lift one leg off the ground, extending it straight up towards the ceiling.','Hold for a moment, then lower your leg back down.','Repeat with the other leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'tFToB7l'),
  ('db-0677', 'ring dips', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Start by hanging from the rings with your arms fully extended and your body straight.','Lower your body by bending your elbows until your shoulders are below your elbows.','Push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'ezTvXcr'),
  ('db-2571', 'rocking frog stretch', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Start by kneeling on the ground with your knees hip-width apart.','Place your hands on the ground in front of you for support.','Slowly lean forward, shifting your weight onto your hands and extending your legs behind you.','Keep your back straight and engage your glutes as you push your hips back and up towards the ceiling.','Hold this position for a few seconds, feeling a stretch in your glutes.','Slowly return to the starting position by bending your knees and lowering your hips back down.','Repeat for the desired number of repetitions.']::text[], '2Dk4xQV'),
  ('db-0678', 'rocky pull-up pulldown', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Stand in front of a pull-up bar with your feet shoulder-width apart.','Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your body straight.','Engage your back muscles and pull your body up towards the bar, leading with your chest.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cQ19bBP'),
  ('db-2208', 'roller back stretch', 'Back', 'Roller', 'spine', ARRAY['hamstrings','glutes']::text[], ARRAY['Start by sitting on the ground with your legs extended in front of you.','Place the roller perpendicular to your body, just below your glutes.','Slowly roll your body backwards, allowing the roller to move up your back.','Continue rolling until the roller reaches your upper back.','Pause for a moment, then slowly roll back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'isofgzg'),
  ('db-2204', 'roller body saw', 'Core', 'Roller', 'abs', ARRAY['shoulders','triceps','core']::text[], ARRAY['Start in a plank position with your forearms on the roller and your body in a straight line.','Engage your core and slowly roll the roller forward, extending your body as far as you can while maintaining control.','Pause for a moment at the furthest point, then slowly roll the roller back towards your starting position.','Repeat for the desired number of repetitions.']::text[], 'XeMvLgE'),
  ('db-2205', 'roller hip lat stretch', 'Legs', 'Roller', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Start by kneeling on the ground with the roller positioned under your hips.','Place your hands on the roller for support.','Slowly roll the roller forward, extending your hips and stretching your glutes.','Hold the stretch for a few seconds, then roll back to the starting position.','Repeat for the desired number of repetitions.']::text[], '0L2KwtI'),
  ('db-2202', 'roller hip stretch', 'Legs', 'Roller', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Start by sitting on the ground with your legs extended in front of you.','Place the roller under your glutes, just above your knees.','Lean back and place your hands on the ground behind you for support.','Engage your glutes and slowly roll the roller forward, bending your knees and bringing them towards your chest.','Pause for a moment at the end of the movement, feeling a stretch in your glutes.','Slowly roll the roller back to the starting position, extending your legs.','Repeat for the desired number of repetitions.']::text[], 'oMypNrz'),
  ('db-2206', 'roller reverse crunch', 'Core', 'Roller', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your arms extended straight above your head and your legs straight out in front of you.','Place the roller between your feet and grip it with your toes.','Engaging your abs, lift your legs off the ground and curl your knees towards your chest, rolling the roller towards your body.','Pause for a moment at the top, then slowly lower your legs back down to the starting position, rolling the roller away from your body.','Repeat for the desired number of repetitions.']::text[], 'SKXQAx3'),
  ('db-2203', 'roller seated shoulder flexor depresor retractor', 'Chest', 'Roller', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Sit on a flat surface with your legs extended in front of you.','Hold the roller with both hands, palms facing down, and place it on your thighs.','Lean forward slightly and roll the roller away from your body, extending your arms straight in front of you.','Pause for a moment, then slowly roll the roller back towards your body, bending your arms and bringing the roller back to your thighs.','Repeat for the desired number of repetitions.']::text[], '8coXSYU'),
  ('db-2209', 'roller seated single leg shoulder flexor depresor retractor', 'Chest', 'Roller', 'pectorals', ARRAY['deltoids','triceps']::text[], ARRAY['Sit on a flat surface with your legs extended in front of you.','Hold the roller with both hands, palms facing down, and place it on your thighs.','Lean back slightly and engage your core muscles.','Raise the roller up to shoulder level, keeping your arms straight.','Slowly lower the roller back down to your thighs.','Repeat for the desired number of repetitions.']::text[], 'CjETvlw'),
  ('db-2207', 'roller side lat stretch', 'Back', 'Roller', 'lats', ARRAY['shoulders','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the roller with both hands in front of your body.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Extend your arms forward and roll the roller down towards your feet, feeling a stretch in your lats.','Hold the stretch for a few seconds, then slowly roll the roller back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'c3Pfhti'),
  ('db-0680', 'rope climb', 'Back', 'Rope', 'upper back', ARRAY['forearms','biceps','shoulders']::text[], ARRAY['Stand facing the rope with your feet shoulder-width apart.','Grab the rope with both hands, palms facing towards you.','Bend your knees slightly and engage your core.','Begin pulling yourself up the rope by alternating hand-over-hand movements.','Use your legs to assist in the upward movement.','Continue climbing until you reach the desired height or the top of the rope.','To descend, reverse the hand-over-hand movement while controlling your descent.','Repeat for the desired number of repetitions.']::text[], 'yaAxcQr'),
  ('db-0685', 'run', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing upright with your feet hip-width apart.','Engage your core and keep your upper body relaxed.','Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.','Maintain a steady pace and continue jogging for the desired duration or distance.','Remember to breathe deeply and maintain good posture throughout the exercise.']::text[], 'oLrKqDH'),
  ('db-0684', 'run (equipment)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start by standing upright with your feet hip-width apart.','Engage your core and keep your upper body relaxed.','Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.','Maintain a steady pace and continue jogging for the desired duration or distance.','Remember to breathe deeply and maintain good posture throughout the exercise.']::text[], 'y5p0H8a'),
  ('db-1585', 'runners stretch', 'Legs', 'Body Weight', 'hamstrings', ARRAY['calves','quadriceps']::text[], ARRAY['Stand with your feet hip-width apart.','Take a step forward with your right foot, keeping your left foot planted.','Bend your right knee and lower your body down, keeping your left leg straight.','Place your hands on your right thigh for support.','Hold the stretch for 20-30 seconds, then switch sides and repeat.']::text[], '0mB6wHO'),
  ('db-0687', 'russian twist', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Sit on the ground with your knees bent and feet flat on the floor.','Lean back slightly while keeping your back straight and your core engaged.','Hold your hands together in front of your chest or hold a weight if desired.','Lift your feet off the ground, balancing on your sit bones.','Twist your torso to the right, bringing your hands or weight towards the right side of your body.','Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body.','Continue alternating sides for the desired number of repetitions.']::text[], 'XVDdcoj'),
  ('db-3012', 'scapula dips', 'Back', 'Body Weight', 'traps', ARRAY['rhomboids','deltoids']::text[], ARRAY['Start by standing with your feet shoulder-width apart and your arms extended in front of you.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Lower your body by bending your elbows and retracting your shoulder blades, as if you are trying to squeeze a pencil between them.','Pause for a moment at the bottom, then push through your hands to extend your elbows and return to the starting position.','Repeat for the desired number of repetitions.']::text[], '7xeukSt'),
  ('db-3021', 'scapula push-up', 'Chest', 'Body Weight', 'serratus anterior', ARRAY['triceps','shoulders']::text[], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line.','Lower your chest towards the ground, keeping your elbows close to your body.','As you lower, squeeze your shoulder blades together and push your chest forward.','Pause for a moment at the bottom, then push back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jV65tKx'),
  ('db-0688', 'scapular pull-up', 'Back', 'Body Weight', 'traps', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.','Retract your shoulder blades by pulling them down and back.','Engage your back muscles and pull your body up towards the bar, focusing on squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'uTBt1HV'),
  ('db-3219', 'scissor jumps (male)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Jump off the ground and simultaneously cross your right leg in front of your left leg.','As you land, quickly switch legs, crossing your left leg in front of your right leg.','Continue alternating legs and jumping as quickly as possible.','Repeat for the desired number of repetitions.']::text[], 'Eh2v5Iu'),
  ('db-1390', 'seated calf stretch (male)', 'Legs', 'Body Weight', 'calves', ARRAY['hamstrings']::text[], ARRAY['Sit on the edge of a chair or bench with your feet flat on the ground.','Extend one leg straight out in front of you, keeping your heel on the ground.','Lean forward slightly, feeling a stretch in your calf muscle.','Hold the stretch for 20-30 seconds.','Switch legs and repeat the stretch.']::text[], '17bqEXD'),
  ('db-1424', 'seated glute stretch', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Bend your right knee and cross your right ankle over your left thigh.','Place your right hand on the ground behind you for support.','With your left hand, gently press down on your right knee to deepen the stretch.','Hold the stretch for 30 seconds to 1 minute.','Switch sides and repeat.']::text[], 'DeDThfG'),
  ('db-0689', 'seated leg raise', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on a flat bench with your back straight and your feet flat on the ground.','Place your hands on the sides of the bench for support.','Keeping your legs straight, slowly raise them up in front of you until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Hgs6Nl1'),
  ('db-0690', 'seated lower back stretch', 'Back', 'Body Weight', 'lats', ARRAY['glutes','hamstrings']::text[], ARRAY['Sit on the edge of a chair with your feet flat on the ground.','Place your hands on your thighs or on the sides of the chair for support.','Slowly lean forward from your hips, keeping your back straight.','Feel the stretch in your lower back and hold for 20-30 seconds.','Slowly return to the starting position and repeat for the desired number of repetitions.']::text[], 'QFmz6ch'),
  ('db-2567', 'seated piriformis stretch', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Bend your right knee and place your right foot on the outside of your left knee.','Place your left elbow on the outside of your right knee and gently twist your torso to the right.','Hold the stretch for 20-30 seconds, then switch sides and repeat.']::text[], 'QY39eBr'),
  ('db-0691', 'seated side crunch (wall)', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Sit on the floor with your back against a wall and your legs extended in front of you.','Bend your knees and place your feet flat on the floor, hip-width apart.','Place your hands behind your head with your elbows pointing outwards.','Engage your abs and lean to one side, bringing your elbow towards your hip.','Pause for a moment, then return to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'Y9hNPcN'),
  ('db-1587', 'seated wide angle pose sequence', 'Legs', 'Body Weight', 'hamstrings', ARRAY['quadriceps','calves']::text[], ARRAY['Sit on the ground with your legs extended in a wide angle.','Flex your feet and engage your quadriceps.','Place your hands on the ground behind you for support.','Keeping your back straight, lean forward from your hips.','Continue leaning forward until you feel a stretch in your hamstrings.','Hold this position for a few breaths.','Slowly release the stretch and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'HIgYKAB'),
  ('db-0697', 'self assisted inverse leg curl', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','calves']::text[], ARRAY['Lie flat on your back on a mat or bench with your legs extended.','Place your hands by your sides or under your glutes for support.','Bend your knees and lift your feet off the ground, bringing your thighs towards your chest.','Pause for a moment at the top, then slowly lower your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'GwYwElT'),
  ('db-1766', 'self assisted inverse leg curl', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','calves']::text[], ARRAY['Lie face down on a leg curl machine with your legs extended and your ankles hooked under the padded lever.','Place your hands on the side handles of the machine for support.','Keeping your upper body stationary, exhale and curl your legs upward as far as possible.','Hold the contracted position for a brief pause as you squeeze your hamstrings.','Slowly lower your legs back to the starting position while inhaling.','Repeat for the desired number of repetitions.']::text[], 'ZSY3MsL'),
  ('db-0696', 'self assisted inverse leg curl (on floor)', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','calves']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Bend your knees and place your feet flat on the ground, hip-width apart.','Lift your hips off the ground, engaging your glutes and hamstrings.','Slowly curl your legs towards your glutes, keeping your hips lifted.','Pause for a moment at the top, then slowly extend your legs back to the starting position.','Lower your hips back down to the ground.','Repeat for the desired number of repetitions.']::text[], 'E4PwJqI'),
  ('db-3222', 'semi squat jump (male)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees and lower your body into a squat position.','Jump explosively, extending your hips and knees while swinging your arms for momentum.','Land softly on the balls of your feet and immediately go into the next repetition.','Repeat for the desired number of repetitions.']::text[], '6FMU51h'),
  ('db-3656', 'short stride run', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Find an open space or a treadmill to perform the exercise.','Stand tall with your feet hip-width apart.','Start jogging in place, lifting your knees high and pumping your arms.','After a few seconds, start taking short strides forward, maintaining a quick pace.','Continue running with short strides for the desired duration or distance.']::text[], 'CcWEoWV'),
  ('db-1763', 'shoulder grip pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with a shoulder-width grip, palms facing away from you.','Hang freely with your arms fully extended.','Engage your back muscles and pull your body up towards the bar until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'YtgD7Xq'),
  ('db-3699', 'shoulder tap', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','triceps']::text[], ARRAY['Start in a high plank position with your hands directly under your shoulders and your body in a straight line.','Engage your core and lift your right hand off the ground, reaching across to tap your left shoulder.','Place your right hand back on the ground and repeat with your left hand tapping your right shoulder.','Continue alternating shoulder taps while keeping your hips and torso stable.','Repeat for the desired number of repetitions.']::text[], 'yRpV5TC'),
  ('db-0699', 'shoulder tap push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','core']::text[], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.','Lower your body towards the ground by bending your elbows, keeping them close to your sides.','As you push back up, lift your right hand off the ground and tap your left shoulder.','Return your right hand to the ground and repeat the push-up, this time lifting your left hand and tapping your right shoulder.','Continue alternating shoulder taps with each push-up repetition.','Maintain a stable core and avoid excessive hip rotation throughout the exercise.','Repeat for the desired number of repetitions.']::text[], 'qEse6fe'),
  ('db-1774', 'side bridge hip abduction', 'Legs', 'Body Weight', 'abductors', ARRAY['glutes','obliques']::text[], ARRAY['Lie on your side with your legs extended and stacked on top of each other.','Prop yourself up on your forearm, keeping your elbow directly below your shoulder.','Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.','While keeping your core engaged, lift your top leg as high as possible without rotating your hips.','Pause for a moment at the top, then lower your leg back down.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'WL4EmxJ'),
  ('db-0705', 'side bridge v. 2', 'Core', 'Body Weight', 'abs', ARRAY['obliques','glutes']::text[], ARRAY['Lie on your side with your legs extended and stacked on top of each other.','Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.','Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.','Hold this position for the desired amount of time.','Lower your hips back down to the starting position.','Repeat on the other side.']::text[], 'RKjH6Lt'),
  ('db-0709', 'side hip (on parallel bars)', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Stand between two parallel bars with your feet shoulder-width apart.','Place your hands on the bars and lift your body off the ground, supporting your weight on your arms.','Engage your abs and slowly lift your legs to the side, keeping them straight.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jTkSc6o'),
  ('db-0710', 'side hip abduction', 'Legs', 'Body Weight', 'abductors', ARRAY['glutes','quadriceps']::text[], ARRAY['Stand with your feet shoulder-width apart and your hands on your hips.','Shift your weight to one leg and lift the opposite leg out to the side, keeping it straight.','Pause for a moment at the top, then slowly lower your leg back down to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], '7WaDzyL'),
  ('db-1358', 'side lying floor stretch', 'Back', 'Body Weight', 'lats', ARRAY['obliques','glutes']::text[], ARRAY['Lie on your side with your legs straight and your bottom arm extended straight overhead.','Bend your top knee and place your foot on the ground in front of your bottom leg.','Reach your top arm over your head and grab onto something stable, like a wall or a piece of furniture.','Slowly lift your bottom leg off the ground, keeping it straight, until you feel a stretch in your side.','Hold the stretch for 20-30 seconds, then slowly lower your leg back down.','Repeat on the other side.']::text[], 'jDOKRM5'),
  ('db-3667', 'side lying hip adduction (male)', 'Legs', 'Body Weight', 'adductors', ARRAY['glutes','hamstrings']::text[], ARRAY['Lie on your side with your legs straight and stacked on top of each other.','Place your bottom arm under your head for support.','Engage your adductors and lift your top leg as high as possible without rotating your hips or leaning backward.','Pause for a moment at the top, then slowly lower your leg back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'c8f5cSY'),
  ('db-1775', 'side plank hip adduction', 'Legs', 'Body Weight', 'adductors', ARRAY['obliques','glutes']::text[], ARRAY['Start by lying on your side with your legs extended and stacked on top of each other.','Prop yourself up on your forearm, keeping your elbow directly below your shoulder.','Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.','While maintaining the side plank position, lift your top leg towards the ceiling, keeping it straight.','Slowly lower your leg back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'VO2qeJg'),
  ('db-0716', 'side push neck stretch', 'Other', 'Body Weight', 'levator scapulae', ARRAY['trapezius','sternocleidomastoid']::text[], ARRAY['Stand or sit up straight with your shoulders relaxed.','Tilt your head to the right, bringing your right ear towards your right shoulder.','Place your right hand on the left side of your head and gently apply pressure to increase the stretch.','Hold the stretch for 15-30 seconds.','Repeat on the other side, tilting your head to the left and applying pressure with your left hand.','Repeat the stretch 2-3 times on each side.']::text[], 'oQRJYkC'),
  ('db-0717', 'side push-up', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders','chest','core']::text[], ARRAY['Start by lying on your side with your legs extended and stacked on top of each other.','Place your bottom hand on the ground directly under your shoulder, fingers pointing forward.','Press through your bottom hand to lift your body off the ground, keeping your legs straight and your core engaged.','Extend your top arm straight up towards the ceiling, creating a straight line from your head to your heels.','Lower your body back down to the starting position with control.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'wpbD28t'),
  ('db-0721', 'side wrist pull stretch', 'Arms', 'Body Weight', 'forearms', ARRAY['wrists','hands']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms extended in front of you.','Extend your right arm out to the side, parallel to the ground, with your palm facing down.','With your left hand, grab your right hand and gently pull it towards your body, feeling a stretch in your right forearm.','Hold the stretch for 15-30 seconds, then release.','Repeat on the other side.']::text[], 'UtmIqcI'),
  ('db-0720', 'side-to-side chin', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your body relaxed.','Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight.','Once your chin is above the bar, lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'isAAZWA'),
  ('db-3213', 'side-to-side toe touch (male)', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms extended to the sides.','Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side.','Return to the starting position and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side.','Repeat the side-to-side bending motion for the desired number of repetitions.']::text[], 'WCAvOfC'),
  ('db-0725', 'single arm push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and one hand placed slightly wider than the other.','Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.','As you lower yourself, shift your weight to one side and lift the opposite arm off the ground, extending it straight out to the side.','Push through your chest and triceps to raise your body back up to the starting position, while simultaneously lowering your extended arm back to the ground.','Repeat the movement, alternating the arm you extend with each repetition.']::text[], 'MUic5zN'),
  ('db-3645', 'single leg bridge with outstretched leg', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Lie on your back with your knees bent and feet flat on the ground.','Extend one leg straight out in front of you.','Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.','Hold for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'rmEukuS'),
  ('db-0727', 'single leg calf raise (on a dumbbell)', 'Legs', 'Dumbbell', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand with your feet hip-width apart and hold a dumbbell in one hand.','Lift one foot off the ground and balance on the other foot.','Slowly raise your heel as high as possible, using your calf muscles.','Pause for a moment at the top, then slowly lower your heel back down.','Repeat for the desired number of repetitions, then switch to the other leg.']::text[], 'fKZgDEO'),
  ('db-0730', 'single leg platform slide', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','quadriceps']::text[], ARRAY['Start by standing with one foot on a platform or slide board.','Bend your knee slightly and slide the foot on the platform backward, extending your leg.','Keep your core engaged and maintain a straight posture throughout the movement.','Slowly return to the starting position by sliding your foot back to the initial position.','Repeat the movement for the desired number of repetitions, then switch legs.']::text[], 'LNE3wfo'),
  ('db-1759', 'single leg squat (pistol) male', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and arms extended in front of you.','Lift your right foot off the ground and extend it forward.','Slowly lower your body down by bending your left knee and pushing your hips back.','Keep your chest up and your back straight as you lower yourself down.','Lower until your left thigh is parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your left heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'nqs5HGV'),
  ('db-1489', 'sissy squat', 'Legs', 'Body Weight', 'quads', ARRAY['calves','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart and your toes pointing slightly outward.','Hold onto a stable object for balance if needed.','Slowly lower your body by bending your knees and leaning back, keeping your torso upright.','Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xdYPUtE'),
  ('db-0735', 'sit-up v. 2', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Bn6TXyO'),
  ('db-3679', 'sit-up with arms on chest', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Cross your arms over your chest.','Engaging your abs, lift your upper body off the ground towards your knees.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '6ZCiYWQ'),
  ('db-3361', 'skater hops', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees slightly and jump to the right, landing on your right foot.','As you land, swing your left leg behind your right leg and tap the ground with your left toes.','Immediately jump to the left, landing on your left foot.','As you land, swing your right leg behind your left leg and tap the ground with your right toes.','Continue alternating sides, jumping and tapping the ground with each leg.','Repeat for the desired number of repetitions.']::text[], 'zfNHMN9'),
  ('db-2142', 'ski ergometer', 'Arms', 'Skierg Machine', 'triceps', ARRAY['shoulders','forearms']::text[], ARRAY['Adjust the seat height and footrests to a comfortable position.','Grasp the handles with an overhand grip, palms facing down.','Sit up straight with your feet flat on the footrests.','Extend your arms straight out in front of you, keeping your elbows slightly bent.','Engage your triceps and push the handles down towards your thighs.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vpQaQkH'),
  ('db-3671', 'ski step', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees slightly and keep your back straight.','Jump to the right, landing on your right foot while swinging your left leg behind your right leg.','Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg.','Continue alternating jumps from side to side, mimicking a skiing motion.','Repeat for the desired number of repetitions.']::text[], '5MRH8H2'),
  ('db-3304', 'skin the cat', 'Back', 'Body Weight', 'upper back', ARRAY['shoulders','core']::text[], ARRAY['Start by hanging from a bar with your arms fully extended and your body relaxed.','Engage your core and lift your legs up, bringing your knees towards your chest.','Continue to lift your legs up and over your head, allowing your body to pass through the arms.','Once your legs are fully extended over your head, begin to lower them back down towards the starting position.','As you lower your legs, allow your body to pass back through the arms until you are hanging with your arms fully extended again.','Repeat for the desired number of repetitions.']::text[], 'MSfvriJ'),
  ('db-1425', 'sled 45 degrees one leg press', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the sled machine to a 45-degree angle.','Sit on the sled machine with your back against the pad and your feet on the footplate.','Place one foot on the footplate and extend your leg, pushing the sled away from you.','Slowly bend your knee and lower the sled back to the starting position.','Repeat with the other leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'WWD6FzI'),
  ('db-0738', 'sled 45в° calf press', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings']::text[], ARRAY['Adjust the sled machine to a 45-degree angle.','Place your feet on the sled platform with your toes pointing forward.','Push the sled platform away from you by extending your ankles and calves.','Pause for a moment at the top, then slowly lower the sled platform back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qCNVnaU'),
  ('db-0739', 'sled 45в° leg press', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat and footplate of the sled machine to a comfortable position.','Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate.','Grip the handles on the sides of the seat for stability.','Push the footplate away from your body by extending your legs, keeping your heels on the footplate.','Continue pushing until your legs are almost fully extended, but without locking your knees.','Pause for a moment at the top of the movement, then slowly lower the footplate back towards your body by bending your knees.','Repeat for the desired number of repetitions.']::text[], '10Z2DXU'),
  ('db-1464', 'sled 45в° leg press (back pov)', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat of the sled machine so that your knees are at a 45-degree angle.','Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate.','Grip the handles on the sides of the seat for stability.','Push the footplate away from your body by extending your legs, keeping your heels on the footplate.','Pause for a moment at the fully extended position.','Slowly bend your knees and lower the footplate back towards your body, controlling the movement.','Repeat for the desired number of repetitions.']::text[], 'yn2lLSI'),
  ('db-1463', 'sled 45° leg press (side pov)', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate.','Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate.','Grip the handles on the sides of the seat for stability.','Push against the footplate to extend your legs, straightening them completely.','Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position.','Repeat for the desired number of repetitions.']::text[], '2Qh2J1e'),
  ('db-0740', 'sled 45в° leg wide press', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the sled machine to a 45-degree angle.','Sit on the sled machine with your back against the pad and your feet on the foot platform.','Position your feet wider than shoulder-width apart.','Push against the foot platform to extend your legs and straighten your knees.','Pause for a moment at the end of the movement, then slowly bend your knees to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'tj41Nu6'),
  ('db-1391', 'sled calf press on leg press', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled.','Place your feet shoulder-width apart on the sled, with your toes pointing forward.','Release the safety handles and push the sled away from you by extending your knees and ankles.','Pause for a moment at the top of the movement, then slowly lower the sled back down by bending your knees and ankles.','Repeat for the desired number of repetitions.']::text[], 'ykHcWme'),
  ('db-0741', 'sled closer hack squat', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the sled machine to a comfortable weight and position yourself with your back against the pad.','Place your feet shoulder-width apart on the platform, toes slightly pointed outwards.','Grip the handles on the sides of the machine for stability.','Engage your core and slowly lower your body by bending your knees and hips, keeping your back straight.','Continue lowering until your thighs are parallel to the ground or slightly below.','Pause for a moment at the bottom, then push through your heels to extend your legs and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'gf3ZjB9'),
  ('db-0742', 'sled forward angled calf raise', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the sled machine to a comfortable weight and position yourself on the machine with your toes on the platform and your heels hanging off.','Place your hands on the handles or the sides of the machine for support.','Engage your calves and slowly raise your heels as high as possible, pushing against the resistance of the sled.','Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'XDOiFns'),
  ('db-0743', 'sled hack squat', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the sled machine to a comfortable position for your height.','Stand with your feet shoulder-width apart on the platform, toes slightly pointed outwards.','Hold onto the handles or bars for stability.','Lower your body by bending your knees and hips, keeping your back straight and chest up.','Continue lowering until your thighs are parallel to the ground or slightly below.','Pause for a moment, then push through your heels to raise your body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Qa55kX1'),
  ('db-2334', 'sled lying calf press', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the sled machine to a comfortable weight.','Sit on the sled machine with your back against the pad and your feet on the platform.','Place your toes and the balls of your feet on the edge of the platform, with your heels hanging off.','Push the platform away from you by extending your ankles, keeping your knees slightly bent.','Continue pushing until your calves are fully contracted.','Hold the contraction for a moment, then slowly lower the platform back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'g376LuL'),
  ('db-0744', 'sled lying squat', 'Legs', 'Sled Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the sled machine to a comfortable weight.','Lie on your back on the sled machine with your feet on the footplate.','Position your feet shoulder-width apart and slightly angled outwards.','Grip the handles of the sled machine for stability.','Engage your glutes and core muscles.','Push through your heels and extend your legs to lift the sled.','Lower the sled back down by bending your knees and hips.','Repeat for the desired number of repetitions.']::text[], '9n2149Z'),
  ('db-1392', 'sled one leg calf press on leg press', 'Legs', 'Sled Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled.','Sit on the machine with your back against the backrest and your feet on the sled, shoulder-width apart.','Place your toes and the balls of your feet on the sled, keeping your heels off.','Push the sled forward by extending your ankles, keeping your knees slightly bent.','Pause for a moment at the top, then slowly lower the sled back down by flexing your ankles.','Repeat for the desired number of repetitions.']::text[], 'u0pLNgz'),
  ('db-1496', 'sledge hammer', 'Core', 'Hammer', 'abs', ARRAY['forearms','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the sledge hammer with both hands.','Engage your core and keep your back straight.','Swing the sledge hammer down towards the ground, using your core and upper body strength.','As you swing down, pivot your hips and transfer the force to the hammer.','Repeat for the desired number of repetitions.']::text[], 'REXmfVC'),
  ('db-0746', 'smith back shrug', 'Back', 'Smith Machine', 'traps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Keep your arms straight and allow the barbell to hang in front of your thighs.','Lift your shoulders straight up towards your ears, squeezing your traps at the top.','Hold for a moment, then lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'MzNnwx9'),
  ('db-0747', 'smith behind neck press', 'Shoulders', 'Smith Machine', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Adjust the seat height of the smith machine so that the bar is at shoulder level.','Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Lift the bar off the rack and step back, maintaining a stable stance.','Lower the bar down to the back of your neck, keeping your elbows pointing forward.','Press the bar up overhead until your arms are fully extended.','Pause for a moment at the top, then slowly lower the bar back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Gpn4ADc'),
  ('db-0748', 'smith bench press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the height of the smith machine bar to chest level.','Lie flat on the bench with your feet firmly planted on the ground.','Grip the bar with an overhand grip slightly wider than shoulder-width apart.','Unrack the bar and lower it towards your chest, keeping your elbows tucked in.','Pause for a moment when the bar touches your chest.','Push the bar back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'trqKQv2'),
  ('db-0749', 'smith bent knee good morning', 'Legs', 'Smith Machine', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Start by standing with your feet shoulder-width apart, toes pointing forward.','Place the barbell across your upper back, resting it on your traps.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.','Engage your glutes and hamstrings to raise your torso back up to the starting position.','Repeat for the desired number of repetitions.']::text[], '1bQkKZK'),
  ('db-1359', 'smith bent over row', 'Back', 'Smith Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up the smith machine with the bar at hip height.','Stand facing the bar with your feet shoulder-width apart.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.','Pull the bar towards your lower chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the bar back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZX9UZmj'),
  ('db-0750', 'smith chair squat', 'Legs', 'Smith Machine', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Adjust the height of the smith machine bar to a comfortable position.','Stand with your feet shoulder-width apart, toes slightly turned out.','Place the barbell across your upper back, resting it on your traps.','Engage your core and keep your chest up as you slowly lower your body by bending your knees and hips.','Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Gu2rNJd'),
  ('db-0751', 'smith close-grip bench press', 'Arms', 'Smith Machine', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Adjust the seat height and position yourself on the bench with your feet flat on the ground.','Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.','Lower the barbell towards your chest, keeping your elbows close to your body.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'WcHl7ru'),
  ('db-0752', 'smith deadlift', 'Legs', 'Smith Machine', 'glutes', ARRAY['hamstrings','quadriceps','lower back']::text[], ARRAY['Set up the smith machine with the bar at hip height.','Stand with your feet shoulder-width apart, toes pointing slightly outward.','Bend at the hips and knees, keeping your back straight and chest up, and grip the bar with an overhand grip slightly wider than shoulder-width apart.','Engage your core and lift the bar by extending your hips and knees, keeping the bar close to your body.','Stand up straight, fully extending your hips and knees.','Lower the bar back down by bending at the hips and knees, maintaining control and keeping your back straight.','Repeat for the desired number of repetitions.']::text[], 'UfePqpx'),
  ('db-0753', 'smith decline bench press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the decline bench to the desired angle.','Lie down on the bench with your feet secured under the foot pads.','Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ETZfAbZ'),
  ('db-0754', 'smith decline reverse-grip press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the smith machine to a decline position.','Lie down on the bench with your feet secured under the foot pads.','Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.','Unrack the barbell and lower it towards your chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'MY9P1WA'),
  ('db-1433', 'smith front squat (clean grip)', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves','core']::text[], ARRAY['Set up the smith machine with the barbell at shoulder height.','Stand facing the barbell with your feet shoulder-width apart.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Step back and position the barbell on your front shoulders, resting it on your collarbone and deltoids.','Keep your chest up, back straight, and core engaged.','Lower your body by bending at the knees and hips, as if sitting back into a chair.','Continue lowering until your thighs are parallel to the ground or slightly below.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'lFhb2Rw'),
  ('db-3281', 'smith full squat', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Set up the smith machine with the barbell at shoulder height.','Stand with your feet shoulder-width apart, toes slightly turned out.','Step under the bar and position it across your upper back, resting on your traps.','Grip the bar with your hands slightly wider than shoulder-width apart.','Unrack the bar and take a step back, maintaining a stable stance.','Keeping your chest up and core engaged, initiate the squat by pushing your hips back and bending your knees.','Lower your body until your thighs are parallel to the ground, or as low as your flexibility allows.','Pause for a moment at the bottom, then drive through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NNoHCEA'),
  ('db-0755', 'smith hack squat', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the barbell on the smith machine to an appropriate height for your body.','Stand with your feet shoulder-width apart, toes slightly pointed outwards.','Position yourself under the barbell, resting it on your upper traps and shoulders.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Engage your core and keep your chest up as you unrack the barbell.','Take a step back and position your feet slightly wider than shoulder-width apart.','Bend your knees and lower your body down, keeping your chest up and back straight.','Continue descending until your thighs are parallel to the ground or slightly below.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZuPXtCK'),
  ('db-0756', 'smith hip raise', 'Core', 'Smith Machine', 'abs', ARRAY['glutes','hamstrings']::text[], ARRAY['Position yourself on the smith machine with your back against the pad and your feet shoulder-width apart.','Place your hands on the barbell, slightly wider than shoulder-width apart.','Engage your core and glutes, then push through your heels to raise your hips off the ground.','Continue lifting until your body forms a straight line from your knees to your shoulders.','Hold for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'CqhoytW'),
  ('db-0757', 'smith incline bench press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Adjust the bench to a 30-45 degree incline.','Sit on the bench with your back flat against the pad and feet firmly on the ground.','Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '5v7KYld'),
  ('db-0758', 'smith incline reverse-grip press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the seat of the smith machine to a comfortable incline angle.','Sit on the machine with your back against the pad and your feet flat on the ground.','Grasp the bar with an overhand grip that is slightly wider than shoulder-width apart.','Unrack the bar and lower it slowly towards your chest, keeping your elbows tucked in.','Pause for a moment when the bar is just above your chest.','Push the bar back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], '78VqWQK'),
  ('db-0759', 'smith incline shoulder raises', 'Chest', 'Smith Machine', 'serratus anterior', ARRAY['deltoids','trapezius']::text[], ARRAY['Adjust the smith machine to an incline position.','Stand facing the machine with your feet shoulder-width apart.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and core engaged.','Raise the barbell up towards the ceiling, leading with your elbows.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ayAHcEm'),
  ('db-0760', 'smith leg press', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat and footplate of the smith machine to a comfortable position.','Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.','Grasp the handles or sides of the machine for stability.','Push the footplate away from you by extending your legs, keeping your back against the backrest.','Pause for a moment at the fully extended position.','Slowly bend your knees and lower the footplate back towards you, returning to the starting position.','Repeat for the desired number of repetitions.']::text[], '7zdxRTl'),
  ('db-1434', 'smith low bar squat', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Set up the smith machine with the barbell at a height that allows you to comfortably rest it on your upper back.','Stand with your feet shoulder-width apart, toes slightly turned outwards.','Step under the bar and position it across your upper back, resting it on your traps.','Grip the bar with your hands slightly wider than shoulder-width apart.','Unrack the bar by straightening your legs and stepping back from the rack.','Take a deep breath and brace your core.','Initiate the squat by pushing your hips back and bending your knees.','Lower your body until your thighs are parallel to the ground or slightly below.','Keep your chest up and your back straight throughout the movement.','Drive through your heels to stand back up, extending your hips and knees.','Repeat for the desired number of repetitions.']::text[], 'RGLscZM'),
  ('db-1683', 'smith machine bicep curl', 'Arms', 'Smith Machine', 'biceps', ARRAY['forearms']::text[], ARRAY['Adjust the height of the smith machine bar to be at waist level.','Stand facing the smith machine with your feet shoulder-width apart.','Grasp the bar with an underhand grip, hands slightly wider than shoulder-width apart.','Keep your elbows close to your sides and your upper arms stationary.','Exhale and curl the bar up towards your shoulders, contracting your biceps.','Pause for a moment at the top of the movement, squeezing your biceps.','Inhale and slowly lower the bar back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'zILLZ98'),
  ('db-1625', 'smith machine decline close grip bench press', 'Arms', 'Smith Machine', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Adjust the bench on the smith machine to a decline position.','Lie down on the bench with your feet firmly planted on the ground.','Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.','Pause for a moment when the barbell is just above your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'yB9SvIF'),
  ('db-1752', 'smith machine incline tricep extension', 'Arms', 'Smith Machine', 'triceps', ARRAY['shoulders']::text[], ARRAY['Adjust the seat of the smith machine so that the bar is at shoulder height.','Sit on the bench with your back against the pad and your feet flat on the ground.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Extend your arms fully, lifting the bar off the rack and holding it directly above your chest.','Lower the bar slowly towards your forehead, keeping your elbows close to your head.','Pause for a moment at the bottom, then push the bar back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'o8aOcrz'),
  ('db-1626', 'smith machine reverse decline close grip bench press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the smith machine to a decline position.','Lie down on the bench with your feet secured under the foot pads.','Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the barbell back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'QyO6Uma'),
  ('db-0761', 'smith narrow row', 'Back', 'Smith Machine', 'upper back', ARRAY['biceps','rear deltoids']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your feet flat on the floor.','Grasp the handles with an overhand grip, slightly narrower than shoulder-width apart.','Keep your back straight and your chest up as you pull the handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JGKowMS'),
  ('db-1360', 'smith one arm row', 'Back', 'Smith Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the height of the smith machine bar to waist level.','Stand facing the smith machine with your feet shoulder-width apart.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Grasp the bar with one hand using an overhand grip, with your palm facing down.','Keep your elbow close to your body and pull the bar towards your waist, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly lower the bar back to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'Q4DSJPC'),
  ('db-1393', 'smith one leg floor calf raise', 'Legs', 'Smith Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Position yourself on the floor under the smith machine bar, facing away from the machine.','Place the balls of your feet on a raised surface, such as a weight plate or block.','Position the smith machine bar across your lower legs, just above your ankles.','Hold onto the bar with your hands for stability.','Raise your heels off the ground by extending your ankles, lifting your body up.','Pause at the top of the movement, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '9GXrTE6'),
  ('db-0762', 'smith rear delt row', 'Shoulders', 'Smith Machine', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the ground.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Keep your back straight and your core engaged as you pull the handles towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'nFUwqG6'),
  ('db-0763', 'smith reverse calf raises', 'Legs', 'Smith Machine', 'calves', ARRAY['hamstrings']::text[], ARRAY['Adjust the smith machine bar to a height just below your shoulders.','Stand facing the bar with your feet hip-width apart and toes pointing forward.','Place the balls of your feet on the edge of a step or platform, with your heels hanging off.','Hold onto the bar for support, keeping your back straight and core engaged.','Raise your heels as high as possible, lifting your body weight onto the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ywaNfuh'),
  ('db-1394', 'smith reverse calf raises', 'Legs', 'Smith Machine', 'calves', ARRAY['hamstrings']::text[], ARRAY['Adjust the smith machine bar to a height just below your shoulders.','Stand facing the bar with your feet hip-width apart and toes pointing forward.','Place the balls of your feet on the edge of a step or platform, with your heels hanging off.','Hold onto the bar for support.','Raise your heels as high as possible, lifting your body up onto your toes.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Lsqrgh4'),
  ('db-1361', 'smith reverse grip bent over row', 'Back', 'Smith Machine', 'upper back', ARRAY['biceps','forearms']::text[], ARRAY['Set up the smith machine with the bar at hip height.','Stand facing the bar with your feet shoulder-width apart.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Grasp the bar with an underhand grip, hands shoulder-width apart.','Pull the bar towards your lower chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower the bar back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aaxA3cm')
